import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import api from "../services/api";
import PostItem from "../components/PostItem";
import toast from "react-hot-toast";

export default function Dashboard() {

  const [items, setItems] = useState([]);
  const [filter, setFilter] = useState("");
  const [loading, setLoading] = useState(true);

  const user = JSON.parse(localStorage.getItem("user") || "null");
  const userId = user?._id || null;

  const loadItems = async () => {

    try {

      setLoading(true);

      const res = await api.get("/items");

      setItems(res.data);

    } catch {

      toast.error("Failed to load items");

    } finally {

      setLoading(false);

    }

  };

  useEffect(() => {
    loadItems();
  }, []);

  const filteredItems = filter
    ? items.filter((i) => i.type === filter)
    : items;

  const lostCount = items.filter((i) => i.type === "lost").length;
  const foundCount = items.filter((i) => i.type === "found").length;

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith("http")) return path;
    return `http://localhost:5000${path.startsWith("/") ? "" : "/"}${path}`;
  };

  if (loading) {

    return (

      <div className="p-8 grid grid-cols-1 md:grid-cols-3 gap-6">

        {[...Array(6)].map((_, i) => (

          <div key={i} className="bg-white p-4 rounded-xl shadow animate-pulse">

            <div className="h-40 bg-gray-200 rounded mb-3"></div>
            <div className="h-4 bg-gray-200 rounded w-3/4 mb-2"></div>
            <div className="h-3 bg-gray-200 rounded w-1/2"></div>

          </div>

        ))}

      </div>

    );

  }

  return (

    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-blue-50 p-6">

      {/* HEADER */}

      <div className="bg-white rounded-xl shadow p-6 mb-8">

        <h1 className="text-3xl font-extrabold">
          <span className="text-blue-600">we</span>
          <span className="text-gray-900">FOUND</span>
          <span className="text-green-600">it</span>
        </h1>

        <p className="text-gray-600 mt-2">
          Secure AI-powered ownership verification 🔐
        </p>

      </div>

      {/* STATS */}

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">

        <StatCard title="Total Items" value={items.length} />
        <StatCard title="Lost Items" value={lostCount} color="red" />
        <StatCard title="Found Items" value={foundCount} color="green" />

      </div>

      {/* POST ITEM */}

      <div className="mb-8">
        <PostItem onPosted={loadItems} />
      </div>

      {/* FILTER */}

      <div className="flex items-center gap-3 mb-6">

        <span className="font-semibold">Filter:</span>

        <select
          className="border p-2 rounded-lg"
          value={filter}
          onChange={(e) => setFilter(e.target.value)}
        >
          <option value="">All</option>
          <option value="lost">Lost</option>
          <option value="found">Found</option>
        </select>

      </div>

      {/* ITEMS */}

      {filteredItems.length === 0 ? (

        <div className="text-center mt-20 text-gray-500">

          <p className="text-xl font-semibold">
            No items found
          </p>

          <p className="text-sm mt-2">
            Try posting a lost or found item.
          </p>

        </div>

      ) : (

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

          {filteredItems.map((item) => {

            const isOwner =
              userId &&
              (typeof item.user === "string"
                ? item.user
                : item.user?._id) === userId;

            const imageUrl =
              item.images?.length > 0
                ? getImageUrl(item.images[0])
                : null;

            return (

              <div
                key={item._id}
                className="bg-white rounded-xl shadow p-4 hover:shadow-xl transition"
              >

                {imageUrl && (

                  <img
                    src={imageUrl}
                    alt={item.title}
                    onError={(e) => {
                      e.target.src =
                        "https://via.placeholder.com/400x200?text=No+Image";
                    }}
                    className="h-40 w-full object-cover rounded-lg mb-3"
                  />

                )}

                <h2 className="text-lg font-bold mb-1">
                  {item.title}
                </h2>

                <p className="text-sm text-gray-600 line-clamp-2">
                  {item.description}
                </p>

                <div className="flex justify-between items-center mt-3">

                  <span
                    className={`text-xs px-3 py-1 rounded-full font-semibold
                    ${item.type === "lost"
                        ? "bg-red-100 text-red-600"
                        : "bg-green-100 text-green-600"
                      }`}
                  >
                    {item.type.toUpperCase()}
                  </span>

                  <span className="text-xs text-gray-400">
                    {new Date(item.createdAt).toLocaleDateString()}
                  </span>

                </div>

                {isOwner && (

                  <div className="text-xs mt-2 text-blue-600 font-semibold">
                    YOUR ITEM
                  </div>

                )}

                <Link
                  to={`/items/${item._id}`}
                  className="block mt-4 text-center bg-blue-600 text-white py-2 rounded-lg hover:bg-blue-700 transition"
                >
                  View Details
                </Link>

              </div>

            );

          })}

        </div>

      )}

    </div>

  );

}

function StatCard({ title, value, color = "blue" }) {

  const map = {
    blue: "text-blue-600 bg-blue-50",
    red: "text-red-600 bg-red-50",
    green: "text-green-600 bg-green-50"
  };

  return (

    <div className={`rounded-xl p-5 shadow ${map[color]}`}>

      <p className="text-sm font-medium">{title}</p>

      <p className="text-3xl font-extrabold mt-2">{value}</p>

    </div>

  );

}
